import{_ as r,o as t,c as n,ae as l}from"./chunks/framework.C8MNLDzb.js";const u=JSON.parse('{"title":"经部 · 儒家经典","description":"","frontmatter":{},"headers":[],"relativePath":"docs/经部/index.md","filePath":"docs/经部/index.md"}'),a={name:"docs/经部/index.md"};function i(s,o,e,g,h,d){return t(),n("div",null,[...o[0]||(o[0]=[l('<h1 id="经部-·-儒家经典" tabindex="-1">经部 · 儒家经典 <a class="header-anchor" href="#经部-·-儒家经典" aria-label="Permalink to &quot;经部 · 儒家经典&quot;">​</a></h1><blockquote><p>经部收录儒家经典及相关注疏作品，是中华学术的根本，以仁义礼智信为核心，阐述修身、齐家、治国、平天下之道。</p></blockquote><hr><h2 id="《诗经》名句" tabindex="-1">《诗经》名句 <a class="header-anchor" href="#《诗经》名句" aria-label="Permalink to &quot;《诗经》名句&quot;">​</a></h2><ol><li><strong>关关雎鸠，在河之洲。窈窕淑女，君子好逑。</strong> —— 关关鸣叫的雎鸠，栖息在河中的小岛上。美丽善良的姑娘，是君子的好配偶。（《诗经·周南·关雎》）</li><li><strong>蒹葭苍苍，白露为霜。所谓伊人，在水一方。</strong> —— 芦苇苍茫茂盛，白露凝结成霜。我所思念的那个人，在水的另一方。（《诗经·秦风·蒹葭》）</li><li><strong>死生契阔，与子成说。执子之手，与子偕老。</strong> —— 生死聚散，我与你立下誓言。牵着你的手，与你一起到老。（《诗经·邶风·击鼓》）</li><li><strong>它山之石，可以攻玉。</strong> —— 其他山上的石头，可以用来打磨玉器。比喻借助外力可以成就事业。（《诗经·小雅·鹤鸣》）</li><li><strong>知我者，谓我心忧；不知我者，谓我何求。</strong> —— 了解我的人，说我心中有忧愁；不了解我的人，说我在追求什么。（《诗经·王风·黍离》）</li><li><strong>桃之夭夭，灼灼其华。之子于归，宜其室家。</strong> —— 桃树茂盛，桃花灿烂。这位姑娘出嫁，定能使家庭和顺。（《诗经·周南·桃夭》）</li><li><strong>投我以木瓜，报之以琼琚。匪报也，永以为好也。</strong> —— 你送我木瓜，我拿美玉回报。不只是回报，是想永远和你相好。（《诗经·卫风·木瓜》）</li><li><strong>战战兢兢，如临深渊，如履薄冰。</strong> —— 小心谨慎，好像站在深渊边缘，好像踩在薄冰上。（《诗经·小雅·小旻》）</li></ol><hr><h2 id="《论语》名句" tabindex="-1">《论语》名句 <a class="header-anchor" href="#《论语》名句" aria-label="Permalink to &quot;《论语》名句&quot;">​</a></h2><ol><li><strong>学而时习之，不亦说乎？</strong> —— 学习知识后时常复习，不是很快乐吗？（《论语·学而》）</li><li><strong>吾十有五而志于学，三十而立，四十而不惑，五十而知天命，六十而耳顺，七十而从心所欲，不逾矩。</strong> —— 我十五岁立志学习，三十岁能立足于世，四十岁能不被迷惑，五十岁能知天命。（《论语·为政》）</li><li><strong>温故而知新，可以为师矣。</strong> —— 温习旧知识能有新收获，就可以当老师了。（《论语·为政》）</li><li><strong>知之为知之，不知为不知，是知也。</strong> —— 知道就是知道，不知道就是不知道，这才是真正的智慧。（《论语·为政》）</li><li><strong>学而不思则罔，思而不学则殆。</strong> —— 只学习不思考就会迷惑，只思考不学习就会精神疲惫。（《论语·为政》）</li><li><strong>君子周而不比，小人比而不周。</strong> —— 君子团结而不勾结，小人勾结而不团结。（《论语·为政》）</li><li><strong>人而无信，不知其可也。</strong> —— 人如果不讲信用，不知道还能做什么。（《论语·为政》）</li><li><strong>君子喻于义，小人喻于利。</strong> —— 君子明白大义，小人只懂得小利。（《论语·里仁》）</li></ol><hr><h2 id="《尚书》名句" tabindex="-1">《尚书》名句 <a class="header-anchor" href="#《尚书》名句" aria-label="Permalink to &quot;《尚书》名句&quot;">​</a></h2><ol><li><strong>人心惟危，道心惟微，惟精惟一，允执厥中。</strong> —— 人心危险难测，道心幽微难明，只有精心体察，专心守住，才能坚持中道。（《尚书·大禹谟》）</li><li><strong>满招损，谦受益，时乃天道。</strong> —— 骄傲自满会招来损害，谦虚谨慎会得到益处，这是天道。（《尚书·大禹谟》）</li><li><strong>玩人丧德，玩物丧志。</strong> —— 玩弄人会丧失品德，玩弄物会丧失志向。（《尚书·旅獒》）</li><li><strong>诗言志，歌永言，声依永，律和声。</strong> —— 诗表达志向，歌延长语言，声音配合音律，音律和谐声音。（《尚书·舜典》）</li></ol><hr><h2 id="《礼记》名句" tabindex="-1">《礼记》名句 <a class="header-anchor" href="#《礼记》名句" aria-label="Permalink to &quot;《礼记》名句&quot;">​</a></h2><ol><li><strong>礼尚往来。往而不来，非礼也；来而不往，亦非礼也。</strong> —— 礼节崇尚往来。去了而不来，不合礼节；来了而不去，也不合礼节。（《礼记·曲礼》）</li><li><strong>玉不琢，不成器；人不学，不知道。</strong> —— 玉石不雕琢，就不能成为器物；人不学习，就不懂得道理。（《礼记·学记》）</li><li><strong>博学之，审问之，慎思之，明辨之，笃行之。</strong> —— 广泛学习，详细询问，慎重思考，明确辨别，切实实行。（《礼记·中庸》）</li><li><strong>一张一弛，文武之道也。</strong> —— 有时紧张有时松弛，这是文王武王治理天下的方法。（《礼记·杂记》）</li></ol><hr><h2 id="《周易》名句" tabindex="-1">《周易》名句 <a class="header-anchor" href="#《周易》名句" aria-label="Permalink to &quot;《周易》名句&quot;">​</a></h2><ol><li><strong>天行健，君子以自强不息。</strong> —— 天道刚健，君子应效法天，永远奋发向上，永不松懈。（《周易·乾卦》）</li><li><strong>地势坤，君子以厚德载物。</strong> —— 大地厚实和顺，君子应效法地，增厚美德，承载万物。（《周易·坤卦》）</li><li><strong>穷则变，变则通，通则久。</strong> —— 困窘时要变革，变革后才能通达，通达后才能长久。（《周易·系辞》）</li><li><strong>二人同心，其利断金。</strong> —— 两个人同心协力，锋利得可以切断金属。（《周易·系辞》）</li></ol><hr><h2 id="《孟子》名句" tabindex="-1">《孟子》名句 <a class="header-anchor" href="#《孟子》名句" aria-label="Permalink to &quot;《孟子》名句&quot;">​</a></h2><ol><li><strong>民为贵，社稷次之，君为轻。</strong> —— 人民最重要，国家其次，国君为轻。（《孟子·尽心》）</li><li><strong>天将降大任于斯人也，必先苦其心志，劳其筋骨，饿其体肤，空乏其身。</strong> —— 上天要把重大使命交给某人，一定要先使他的心意苦恼，筋骨劳累，饥饿消瘦，身无分文。（《孟子·告子》）</li><li><strong>生于忧患，死于安乐。</strong> —— 在忧患中生存，在安乐中灭亡。（《孟子·告子》）</li><li><strong>得道者多助，失道者寡助。</strong> —— 得到道义的人，帮助他的人就多；失去道义的人，帮助他的人就少。（《孟子·公孙丑》）</li><li><strong>富贵不能淫，贫贱不能移，威武不能屈。</strong> —— 富贵不能使心志扰乱，贫贱不能使节操改变，威武不能使志向屈服。（《孟子·滕文公》）</li></ol><hr><h2 id="左传典故" tabindex="-1">左传典故 <a class="header-anchor" href="#左传典故" aria-label="Permalink to &quot;左传典故&quot;">​</a></h2><h3 id="曹刿论战" tabindex="-1">曹刿论战 <a class="header-anchor" href="#曹刿论战" aria-label="Permalink to &quot;曹刿论战&quot;">​</a></h3><p><strong>典故：</strong> 齐国攻打鲁国，曹刿请求面见鲁庄公。庄公说：&quot;小大之狱，虽不能察，必以情。&quot;曹刿说：&quot;忠之属也，可以一战。&quot; <strong>出处：</strong> 《左传·庄公十年》 <strong>释义：</strong> &quot;一鼓作气&quot;出自此典，比喻趁气势正盛时一举取胜。</p><h3 id="退避三舍" tabindex="-1">退避三舍 <a class="header-anchor" href="#退避三舍" aria-label="Permalink to &quot;退避三舍&quot;">​</a></h3><p><strong>典故：</strong> 晋公子重耳流亡楚国时，许诺若归国遇楚军将退避三舍。后来城濮之战，晋文公果然退避三舍以报楚王之恩。 <strong>出处：</strong> 《左传·僖公二十三年》《僖公二十八年》 <strong>释义：</strong> 比喻对人让步或回避，不敢竞争。</p><h3 id="弦高犒师" tabindex="-1">弦高犒师 <a class="header-anchor" href="#弦高犒师" aria-label="Permalink to &quot;弦高犒师&quot;">​</a></h3><p><strong>典故：</strong> 秦军偷袭郑国，商人弦高一面派人回国报信，一面以十二头牛犒劳秦军，假装郑国早已有备。秦军以为郑国有防备，遂撤军。 <strong>出处：</strong> 《左传·僖公三十三年》 <strong>释义：</strong> 形容临危不惧，以智谋保护国家利益。</p><hr><h2 id="分类说明" tabindex="-1">分类说明 <a class="header-anchor" href="#分类说明" aria-label="Permalink to &quot;分类说明&quot;">​</a></h2><ul><li><strong>《诗》</strong> — 《诗经》，我国最早的诗歌总集，305篇</li><li><strong>《书》</strong> — 《尚书》，上古历史文献汇编</li><li><strong>《礼》</strong> — 《礼记》，礼仪制度的理论阐述</li><li><strong>《易》</strong> — 《周易》，占卜与哲学经典</li><li><strong>《春秋》</strong> — 鲁国编年史，微言大义</li></ul><hr><p><em>本文库由 GuoAgent 运营维护</em></p>',33)])])}const q=r(a,[["render",i]]);export{u as __pageData,q as default};
